import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, relative, resolve, sep } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = fileURLToPath(new URL('..', import.meta.url));
const entryFile = resolve(root, 'js/main.js');
const outputFile = resolve(root, 'dist/rollo.bundle.js');
const modules = new Map();

function moduleId(file) {
  return relative(root, file).split(sep).join('/');
}

function resolveImport(fromFile, specifier) {
  if (!specifier.startsWith('.')) {
    throw new Error(`외부 모듈은 번들할 수 없습니다: ${specifier}`);
  }
  return resolve(dirname(fromFile), specifier);
}

async function collect(file) {
  const id = moduleId(file);
  if (modules.has(id)) return;

  let source = await readFile(file, 'utf8');
  const dependencies = [];
  source = source.replace(
    /import\s*\{([^}]+)\}\s*from\s*['"]([^'"]+)['"];?/g,
    (_match, names, specifier) => {
      const dependencyFile = resolveImport(file, specifier);
      dependencies.push(dependencyFile);
      return `const {${names}} = __require(${JSON.stringify(moduleId(dependencyFile))});`;
    },
  );

  const exports = new Set();
  source = source.replace(
    /export\s+(class|function|const|let|var)\s+([A-Za-z_$][\w$]*)/g,
    (_match, declaration, name) => {
      exports.add(name);
      return `${declaration} ${name}`;
    },
  );
  source = source.replace(/export\s*\{([^}]+)\};?/g, (_match, names) => {
    for (const item of names.split(',')) {
      const name = item.trim().split(/\s+as\s+/)[0];
      if (name) exports.add(name);
    }
    return '';
  });

  modules.set(id, `${source}\nObject.assign(exports, { ${[...exports].join(', ')} });`);
  await Promise.all(dependencies.map(collect));
}

await collect(entryFile);

const moduleTable = [...modules]
  .map(([id, source]) => `${JSON.stringify(id)}: (__require, exports) => {\n${source}\n}`)
  .join(',\n');

const bundle = `/* Generated by scripts/build-bundle.mjs. Do not edit directly. */
(() => {
  'use strict';
  const __modules = {
${moduleTable}
  };
  const __cache = Object.create(null);
  function __require(id) {
    if (__cache[id]) return __cache[id];
    const factory = __modules[id];
    if (!factory) throw new Error('번들 모듈 누락: ' + id);
    const exports = {};
    __cache[id] = exports;
    factory(__require, exports);
    return exports;
  }
  __require('js/main.js');
})();
`;

await mkdir(dirname(outputFile), { recursive: true });
await writeFile(outputFile, bundle, 'utf8');
process.stdout.write(`BUILD ${moduleId(outputFile)} modules=${modules.size}\n`);
